diff --git a/clients/src/main/java/org/apache/kafka/clients/producer/ProducerRecord.java b/clients/src/main/java/org/apache/kafka/clients/producer/ProducerRecord.java
index 3e43f27..fcfbfb5 100644
--- a/clients/src/main/java/org/apache/kafka/clients/producer/ProducerRecord.java
+++ b/clients/src/main/java/org/apache/kafka/clients/producer/ProducerRecord.java
@@ -222,4 +222,60 @@ public class ProducerRecord<K, V> {
         result = 31 * result + (timestamp != null ? timestamp.hashCode() : 0);
         return result;
     }
+
+    /**
+     * Creates a new {@link Builder} for fluent construction of a {@code ProducerRecord}.
+     */
+    public static <K, V> Builder<K, V> builder(String topic, V value) {
+        return new Builder<>(topic, value);
+    }
+
+    public static final class Builder<K, V> {
+        private final String topic;
+        private final V value;
+        private Integer partition;
+        private Long timestamp;
+        private K key;
+        private Iterable<Header> headers;
+
+        private Builder(String topic, V value) {
+            if (topic == null)
+                throw new IllegalArgumentException("Topic cannot be null.");
+            this.topic = topic;
+            this.value = value;
+        }
+
+        public Builder<K, V> partition(Integer partition) {
+            this.partition = partition;
+            return this;
+        }
+
+        public Builder<K, V> timestamp(Long timestamp) {
+            this.timestamp = timestamp;
+            return this;
+        }
+
+        public Builder<K, V> key(K key) {
+            this.key = key;
+            return this;
+        }
+
+        public Builder<K, V> headers(Iterable<Header> headers) {
+            this.headers = headers;
+            return this;
+        }
+
+        public ProducerRecord<K, V> build() {
+            return new ProducerRecord<>(topic, partition, timestamp, key, value, headers);
+        }
+    }
 }
